import { useCallback, useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { Sparkles, Library, Loader2, ArrowRight } from "lucide-react";
import { UploadDropzone } from "#components/upload-dropzone";
import { DocumentCard } from "#components/document-card";
import { Skeleton } from "#components/ui/skeleton";
import { listDocuments, createPlan } from "#lib/api";
import type { DocumentSummary } from "#lib/types";

export function LibraryPage() {
  const [docs, setDocs] = useState<DocumentSummary[]>([]);
  const [loading, setLoading] = useState(true);
  const [planning, setPlanning] = useState<number | null>(null);
  const navigate = useNavigate();

  const refresh = useCallback(async () => {
    setLoading(true);
    try {
      const data = await listDocuments();
      setDocs(data);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    void refresh();
  }, [refresh]);

  useEffect(() => {
    const anyProcessing = docs.some((d) => d.status === "processing");
    if (anyProcessing) {
      const t = setTimeout(() => void refresh(), 3000);
      return () => clearTimeout(t);
    }
  }, [docs, refresh]);

  const handleUploaded = useCallback(async (documentId: number) => {
    await refresh();
    setPlanning(documentId);
    try {
      const plan = await createPlan(documentId);
      navigate(`/learn/${plan.id}`);
    } catch {
      // user will see doc in library; they can retry
    } finally {
      setPlanning(null);
    }
  }, [navigate, refresh]);

  return (
    <div className="space-y-10">
      <section className="relative overflow-hidden rounded-3xl border border-border bg-card p-8 sm:p-12">
        <div className="absolute inset-0 bg-grid-pattern opacity-60" />
        <div className="absolute inset-0 bg-radial-glow" />
        <div className="relative z-10 max-w-2xl">
          <span className="inline-flex items-center gap-1.5 rounded-full border border-primary/30 bg-primary/10 px-3 py-1 text-xs font-medium text-primary">
            <Sparkles className="size-3.5" />
            Human-in-the-loop learning agent
          </span>
          <h1 className="mt-4 text-3xl font-bold tracking-tight sm:text-4xl">
            Turn any PDF into an interactive lesson.
          </h1>
          <p className="mt-3 text-base text-muted-foreground">
            Upload a document, review the proposed learning path, then learn by
            answering quizzes with instant feedback, hints, and explanations —
            grounded in your PDF.
          </p>
          <div className="mt-6">
            <UploadDropzone onUploaded={handleUploaded} />
          </div>
        </div>
      </section>

      <section>
        <div className="flex items-center justify-between">
          <div className="flex items-center gap-2">
            <Library className="size-5 text-primary" />
            <h2 className="text-lg font-semibold tracking-tight">
              Your library
            </h2>
          </div>
          {docs.length > 0 && (
            <span className="text-xs text-muted-foreground">
              {docs.length} document{docs.length > 1 ? "s" : ""}
            </span>
          )}
        </div>

        {loading ? (
          <div className="mt-4 grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
            {Array.from({ length: 3 }).map((_, i) => (
              <Skeleton key={i} className="h-44 w-full rounded-2xl" />
            ))}
          </div>
        ) : docs.length === 0 ? (
          <div className="mt-4 rounded-2xl border border-dashed border-border bg-card p-10 text-center text-sm text-muted-foreground">
            No documents yet. Upload your first PDF above to begin.
          </div>
        ) : (
          <div className="mt-4 grid gap-4 sm:grid-cols-2 lg:grid-cols-3">
            {docs.map((doc) => (
              <DocumentCard key={doc.id} doc={doc} />
            ))}
          </div>
        )}
      </section>

      {planning !== null && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-background/70 backdrop-blur-sm">
          <div className="flex items-center gap-3 rounded-2xl border border-border bg-card px-6 py-4 shadow-xl">
            <Loader2 className="size-5 animate-spin text-primary" />
            <div>
              <p className="text-sm font-medium">Drafting your lesson plan...</p>
              <p className="text-xs text-muted-foreground">
                Analyzing the PDF content with the agent.
              </p>
            </div>
          </div>
        </div>
      )}

      <footer className="flex items-center justify-center gap-2 pt-6 text-xs text-muted-foreground">
        <span>Built with LangChain, Fastify, SQLite, and Shadcn UI</span>
        <ArrowRight className="size-3" />
      </footer>
    </div>
  );
}

