import type { FastifyInstance } from "fastify";
import * as svc from "../services/learning.ts";

export async function routes(app: FastifyInstance) {
  app.get("/api/documents", async () => {
    return svc.listDocuments();
  });

  app.get("/api/documents/:id", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const doc = await svc.getDocument(id);
    if (!doc) return reply.code(404).send({ error: "Document not found" });
    return doc;
  });

  app.get("/api/documents/:id/plans", async (req) => {
    const id = Number((req.params as { id: string }).id);
    return svc.getPlansForDocument(id);
  });

  app.post("/api/documents/:id/plans", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    try {
      const plan = await svc.createPlan(id);
      return reply.code(201).send(plan);
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.get("/api/lesson-plans/:id", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const plan = await svc.getPlan(id);
    if (!plan) return reply.code(404).send({ error: "Plan not found" });
    return plan;
  });

  app.post("/api/lesson-plans/:id/approve", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    try {
      const plan = await svc.approvePlan(id);
      return plan;
    } catch (err) {
      return reply
        .code(404)
        .send({ error: (err as Error).message });
    }
  });

  app.get("/api/lesson-plans/:id/quizzes", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    try {
      const quizzes = await svc.getAllQuizzes(id);
      return quizzes;
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.post("/api/lesson-plans/:id/quizzes", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const body = req.body as { objectiveIndex?: number };
    const objectiveIndex = body?.objectiveIndex;
    if (objectiveIndex === undefined) {
      return reply
        .code(400)
        .send({ error: "objectiveIndex is required" });
    }
    try {
      return await svc.getOrCreateQuiz(id, objectiveIndex);
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.post("/api/quizzes/:id/explain", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    try {
      return await svc.getExplanation(id);
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.post("/api/quizzes/:id/check", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const body = (req.body ?? {}) as { learnerIndex?: number };
    if (body.learnerIndex === undefined || body.learnerIndex === null) {
      return reply
        .code(400)
        .send({ error: "learnerIndex is required" });
    }
    try {
      return await svc.checkAnswer(id, Number(body.learnerIndex));
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.post("/api/quizzes/:id/hint", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const body = (req.body ?? {}) as { previousGuessIndex?: number | null };
    try {
      const hint = await svc.getHint(
        id,
        body.previousGuessIndex ?? null,
      );
      return { hint };
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.post("/api/quizzes/:id/learn-more", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const body = req.body as {
      learnerQuestion?: string;
      history?: Array<{
        role: "user" | "assistant";
        content: string;
      }>;
    };
    if (!body?.learnerQuestion) {
      return reply
        .code(400)
        .send({ error: "learnerQuestion is required" });
    }
    try {
      const message = await svc.learnMoreAboutQuiz(
        id,
        body.learnerQuestion,
        body.history ?? [],
      );
      return { message };
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.post("/api/lesson-plans/:id/complete", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const body = req.body as {
      answers?: Array<{
        quizId: number;
        learnerIndex: number | null;
        attempts: number;
      }>;
    };
    if (!body?.answers) {
      return reply
        .code(400)
        .send({ error: "answers is required" });
    }
    try {
      return await svc.completeAttempt(id, { answers: body.answers });
    } catch (err) {
      return reply
        .code(400)
        .send({ error: (err as Error).message });
    }
  });

  app.get("/api/lesson-plans/:id/attempts", async (req) => {
    const id = Number((req.params as { id: string }).id);
    return svc.listAttempts(id);
  });

  app.get("/api/attempts/:id", async (req, reply) => {
    const id = Number((req.params as { id: string }).id);
    const attempt = await svc.getAttempt(id);
    if (!attempt)
      return reply.code(404).send({ error: "Attempt not found" });
    return attempt;
  });
}

