                <div className="min-w-0 flex-1">
                  <p className="text-sm font-medium leading-relaxed">
                    {obj.text}
                  </p>
                  <p className="mt-1 text-xs text-muted-foreground">
                    Topic: <span className="font-medium">{obj.topic}</span>
                  </p>
                </div>
              </li>
            ))}
          </ol>

          <div className="mt-6 rounded-xl border border-primary/20 bg-primary/5 p-4 text-sm text-foreground">
            <div className="flex items-start gap-2">
              <CheckCircle2 className="size-4 shrink-0 translate-y-0.5 text-primary" />
              <div>
                <p className="font-medium">Review & approve to begin</p>
                <p className="mt-0.5 text-xs text-muted-foreground">
                  The agent will generate one MCQ per objective. You'll get
                  hints and explanations, and can ask follow-up questions at any
                  time.
                </p>
              </div>
            </div>
          </div>

          <div className="mt-6 flex items-center justify-end gap-2">
            <Button variant="ghost" onClick={onBack}>
              Cancel
            </Button>
            <Button
              className={cn("gap-1.5")}
              onClick={handleApprove}
              disabled={approving}
            >
              {approving ? (
                <>
                  <Loader2 className="size-4 animate-spin" />
                  Approving...
                </>
              ) : (
              <>
                Approve & start learning
                <ArrowRight className="size-4" />
              </>
              )}
            </Button>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

